+        public void UpdateTicksForSpeedChange(uint newTotalTicks)
+        {
+            if (TotalTicks == newTotalTicks) return;
+
+            // 既存進捗率を保ったまま、新しい搬送時間へ再計算する
+            // Recalculate against the new transit time while preserving existing progress
