1037	+        {
1038	+            new MoorestechServerDIContainerGenerator().Create(new MoorestechServerDIContainerOptions(TestModDirectory.ForUnitTestModDirectory));
1039	+
1040	+            // 対象機械を配置し、明示倍率が読み込まれていることを確認する
