1047	+            Assert.AreEqual(0.25f, idlePowerRate, 0.0001f);
1048	+
1049	+            // 入力が無いIdle状態では要求電力がidlePowerRate分だけ下がる
1050	+            // In Idle without inputs, requested power is reduced by idlePowerRate
1051	+            Assert.AreEqual(param.RequiredPower * idlePowerRate, electric.RequestEnergy.AsPrimitive(), 0.0001f);
1052	+
1053	+            // レシピ入力を投入して加工が始まるとフル要求へ戻る
1054	+            // Once recipe inputs start processing, demand returns to full power
1055	+            InsertRecipeInputs(block, GetMachineRecipe());
1056	+            processor.SupplyPower(processor.RequestPower);
1057	+            GameUpdater.UpdateOneTick();
1058	+            Assert.AreEqual(ProcessState.Processing, processor.CurrentState);
1059	+            Assert.AreEqual(param.RequiredPower, electric.RequestEnergy.AsPrimitive(), 0.0001f);
1060	+        }
